export const createCareerCounselorChat = (): Chat => {
  return ai.chats.create({
    model: 'gemini-3-flash-preview',
    config: {
      systemInstruction: `You are an empathetic and expert Career Counselor AI for a platform called JobCrafting. 
      Your goal is to help the user "job craft" - reshape their career around their true interests, skills, and life goals.

      1. Ask probing questions about their past experience, what they loved/hated about previous jobs, their hobbies, and financial goals.
      2. Suggest potential career paths or "job modifications" that align with their answers.
      3. Be encouraging but realistic.
      4. Keep responses concise and conversational (under 100 words usually).

      At any point, if you have identified a strong candidate for a job role, explicitly mention it as a "Recommended Career Path".`
    }
  });
};

export const enhanceCV = async (currentCV: string, targetJob: string) => {
  const prompt = `
    I am targeting the role of: ${targetJob}.
    Here is my current resume/CV content:
    "${currentCV}"

    Please rewrite and optimize this CV to better align with the ${targetJob} role. 
    - Highlight transferable skills.
    - Use strong action verbs.
    - Improve clarity and impact.
    - Return the result in Markdown format with clear sections.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
