import React, { useEffect, useState } from 'react';
import { HashRouter, Switch, Route, Redirect } from 'react-router-dom';
import { onAuthStateChanged, User } from 'firebase/auth';
import { auth } from './firebase';
import { UserProfile } from './types';
import Auth from './components/Auth';
import Layout from './components/Layout';
import Chatbot from './components/Chatbot';
import CVEnhancer from './components/CVEnhancer';
import JobFinder from './components/JobFinder';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      if (currentUser) {
        // Load profile from localStorage to simulate DB persistence for demo
        const savedProfile = localStorage.getItem(`jobcraft_profile_${currentUser.uid}`);
        if (savedProfile) {
          setProfile(JSON.parse(savedProfile));
        } else {
          setProfile({
            uid: currentUser.uid,
            email: currentUser.email,
            displayName: currentUser.displayName,
            hasOnboarded: false
          });
        }
      } else {
        setProfile(null);
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  const handleOnboardingComplete = (targetJob: string) => {
    if (!user || !profile) return;

    const newProfile = {
      ...profile,
      targetJob,
      hasOnboarded: true
    };

    setProfile(newProfile);
    localStorage.setItem(`jobcraft_profile_${user.uid}`, JSON.stringify(newProfile));
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="w-16 h-16 border-4 border-brand-200 border-t-brand-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <HashRouter>
      <Switch>
        <Route 
          path="/login" 
          render={() => !user ? <Auth /> : <Redirect to="/dashboard" />} 
        />

        <Route
          path="/onboarding"
          render={() =>
            user ? (
              !profile?.hasOnboarded ? (
                <div className="min-h-screen bg-gray-100 p-8 flex flex-col items-center justify-center">
                   <div className="w-full max-w-4xl mb-8 text-center">
                     <h1 className="text-3xl font-bold text-gray-800 mb-2">Welcome, {user.displayName?.split(' ')[0] || 'Traveler'}</h1>
                     <p className="text-gray-600">Let's craft your career journey together.</p>
                   </div>
                   <div className="w-full">
                     <Chatbot onComplete={handleOnboardingComplete} />
                   </div>
                </div>
              ) : (
                <Redirect to="/dashboard" />
              )
            ) : (
              <Redirect to="/login" />
            )
          }
        />

        <Route
          path="/dashboard"
          render={() =>
            user && profile?.hasOnboarded ? (
              <Layout profile={profile}>
                <div className="space-y-6">
                  <div className="bg-gradient-to-r from-brand-600 to-brand-800 rounded-2xl p-8 text-white shadow-xl">
                    <h1 className="text-3xl font-bold mb-2">Welcome Back!</h1>
                    <p className="opacity-90 text-lg">Your current target: <span className="font-bold border-b border-brand-400 pb-1">{profile.targetJob}</span></p>
                  </div>

                  <div className="grid md:grid-cols-2 gap-6">
                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
                      <h3 className="text-xl font-bold text-gray-800 mb-2">Action Items</h3>
                      <ul className="space-y-3">
                        <li className="flex items-center gap-3 text-gray-600">
                          <span className="w-6 h-6 rounded-full bg-green-100 text-green-600 flex items-center justify-center text-xs">✓</span>
                          Completed Career Assessment
                        </li>
                        <li className="flex items-center gap-3 text-gray-600">
                          <span className="w-6 h-6 rounded-full bg-brand-100 text-brand-600 flex items-center justify-center text-xs">2</span>
                          Upload your CV for AI Enhancement
                        </li>
                         <li className="flex items-center gap-3 text-gray-600">
                          <span className="w-6 h-6 rounded-full bg-gray-100 text-gray-600 flex items-center justify-center text-xs">3</span>
                          Review matched job listings
                        </li>
                      </ul>
                    </div>

                    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow flex flex-col justify-center items-center text-center">
                       <div className="w-12 h-12 bg-brand-50 text-brand-600 rounded-full flex items-center justify-center mb-4">
                         <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                       </div>
                       <h3 className="font-bold text-gray-900">Career Tip</h3>
                       <p className="text-sm text-gray-500 mt-2">"Job crafting isn't just about changing jobs, it's about changing how you perceive your current role."</p>
                    </div>
                  </div>
                </div>
              </Layout>
            ) : (
               user ? <Redirect to="/onboarding" /> : <Redirect to="/login" />
            )
          }
        />

        <Route
          path="/cv-enhancer"
          render={() =>
            user && profile?.hasOnboarded ? (
              <Layout profile={profile}>
                <CVEnhancer targetJob={profile.targetJob || ''} />
              </Layout>
            ) : (
              <Redirect to="/" />
            )
          }
        />

        <Route
          path="/jobs"
          render={() =>
            user && profile?.hasOnboarded ? (
              <Layout profile={profile}>
                <JobFinder targetJob={profile.targetJob || ''} />
              </Layout>
            ) : (
              <Redirect to="/" />
            )
          }
        />

        <Route
          path="/freelance"
          render={() =>
             user && profile?.hasOnboarded ? (
              <Layout profile={profile}>
                <JobFinder targetJob={profile.targetJob || ''} isFreelance={true} />
              </Layout>
             ) : (
              <Redirect to="/" />
             )
          }
        />

        <Route path="/" exact>
          <Redirect to={user ? "/dashboard" : "/login"} />
        </Route>
      </Switch>
    </HashRouter>
  );
};

export default App;
